#include<bits/stdc++.h>
using namespace std;
long long a[500010],b[500010];
struct segment_tree
{
    struct node
    {
        long long l,r,sum,gcd;
        long long lson,rson;
    }a[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum);
        a[x].gcd=gcd(a[a[x].lson].gcd,a[a[x].rson].gcd);
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum=a[x].gcd=b[l];
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long p,long long z)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].gcd+=z;
            a[x].sum+=z;
            return;
        }
        add(a[x].lson,p,z);
        add(a[x].rson,p,z);
        pushup(x);
    }
    long long getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        return (getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r));
    }
    long long getgcd(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].gcd;
        }
        return gcd(getgcd(a[x].lson,l,r),getgcd(a[x].rson,l,r));
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        b[i]=a[i]-a[i-1];
    }
    t.init(1,n);
    while(m--)
    {
        char op;
        cin>>op;
        long long l,r,x;
        scanf("%lld%lld",&l,&r);
        if(op=='C')
        {
            scanf("%lld",&x);
            t.add(1,l,x);
            t.add(1,r+1,-x);
        }
        else
        {
            printf("%lld\n",abs(gcd(t.getsum(1,1,l),t.getgcd(1,l+1,r))));
        }
    }
    return 0;
}
